def verify_checksum(filepath, expected_sha256):
    sha256_hash = hashlib.sha256()
    with open(filepath, "rb") as f:
        for byte_block in iter(lambda: f.read(4096), b""):
            sha256_hash.update(byte_block)
    return sha256_hash.hexdigest() == expected_sha256


def validate_url(url):
    from urllib.parse import urlparse
    parsed = urlparse(url)
    if parsed.scheme not in ['https']:
        raise ValueError(f"Only HTTPS URLs are allowed: {url}")
    if parsed.netloc not in ALLOWED_DOMAINS:
        raise ValueError(f"Domain not in allowed list: {parsed.netloc}")
    return True


def download_resource(url, destination, expected_checksum):
    try:
        validate_url(url)
        print(f"Downloading {url} to {destination}")
        
        req = urllib.request.Request(url)
        req.add_header('User-Agent', f'{PACKAGE_NAME}/{VERSION}')
        
        with urllib.request.urlopen(req, timeout=30) as response:
            with open(destination, 'wb') as out_file:
                out_file.write(response.read())
        
        if not verify_checksum(destination, expected_checksum):
            os.remove(destination)
            raise ValueError(f"Checksum verification failed for {destination}")
        
        print(f"Successfully downloaded and verified {destination}")
        return True
        
    except urllib.error.URLError as e:
        print(f"Failed to download {url}: {e}")
        return False
    except Exception as e:
        print(f"Error downloading resource: {e}")
        if os.path.exists(destination):
            os.remove(destination)
        return False


